import React, { useState } from 'react';

// Demo component to show the modern movie card design
const MovieCard = ({ 
  movie, 
  showRecommendationScore = false, 
  recommendationSources = [], 
  onRatingUpdate = null 
}) => {
  const isAuthenticated = true; // Demo: user is authenticated
  const [showQuickRate, setShowQuickRate] = useState(false);
  const [quickRating, setQuickRating] = useState(0);
  const [hoverRating, setHoverRating] = useState(0);
  const [isRating, setIsRating] = useState(false);
  const [userRating, setUserRating] = useState(null);

  const handleQuickRate = async (rating) => {
    if (!isAuthenticated) return;

    setIsRating(true);
    // Simulate API call
    setTimeout(() => {
      setUserRating({ rating });
      setShowQuickRate(false);
      setIsRating(false);

      if (onRatingUpdate) {
        onRatingUpdate(movie.id, rating);
      }
    }, 1000);
  };

  const renderStars = (rating, interactive = false, size = 'small') => {
    const stars = [];
    const maxStars = 5;
    const displayRating = interactive ? (hoverRating || quickRating) : rating;

    for (let i = 1; i <= maxStars; i++) {
      const filled = i <= displayRating;
      stars.push(
        <button
          key={i}
          className={`
            w-5 h-5 transition-all duration-200 ease-out
            ${interactive ? 'cursor-pointer hover:scale-110 active:scale-95' : 'cursor-default'}
            ${filled ? 'text-yellow-400 drop-shadow-sm' : 'text-gray-300'}
            ${interactive && hoverRating >= i ? 'text-yellow-300 scale-105' : ''}
          `}
          onClick={interactive ? () => {
            setQuickRating(i);
            handleQuickRate(i);
          } : undefined}
          onMouseEnter={interactive ? () => setHoverRating(i) : undefined}
          onMouseLeave={interactive ? () => setHoverRating(0) : undefined}
          disabled={!interactive}
          type="button"
        >
          <svg viewBox="0 0 24 24" fill="currentColor" className="w-full h-full">
            <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
          </svg>
        </button>
      );
    }

    return <div className="flex items-center gap-0.5">{stars}</div>;
  };

  const getRecommendationBadge = () => {
    if (!showRecommendationScore || !recommendationSources || recommendationSources.length === 0) {
      return null;
    }

    const badgeText = recommendationSources.includes('collaborative') && recommendationSources.includes('content')
      ? 'Perfect Match'
      : recommendationSources.includes('collaborative')
        ? 'Similar Users'
        : recommendationSources.includes('content')
          ? 'Your Taste'
          : 'Recommended';

    const badgeClass = recommendationSources.length > 1 
      ? 'bg-gradient-to-r from-green-500 to-emerald-500' 
      : recommendationSources.includes('collaborative')
        ? 'bg-gradient-to-r from-blue-500 to-cyan-500'
        : 'bg-gradient-to-r from-orange-500 to-amber-500';

    return (
      <div className={`
        absolute top-3 right-3 z-10 px-3 py-1 rounded-full text-xs font-semibold text-white
        shadow-lg backdrop-blur-sm ${badgeClass}
        animate-pulse
      `}>
        {badgeText}
      </div>
    );
  };

  const formatYear = (year) => {
    return year ? `(${year})` : '';
  };

  const truncateTitle = (title, maxLength = 30) => {
    if (!title) return '';
    return title.length > maxLength ? `${title.substring(0, maxLength)}...` : title;
  };

  const truncatePlot = (plot, maxLength = 100) => {
    if (!plot) return '';
    return plot.length > maxLength ? `${plot.substring(0, maxLength)}...` : plot;
  };

  return (
    <div className="group relative bg-white rounded-2xl shadow-lg hover:shadow-2xl transition-all duration-300 ease-out overflow-hidden border border-gray-100 hover:border-gray-200 max-w-sm">
      {getRecommendationBadge()}

      <div className="cursor-pointer">
        <div className="relative overflow-hidden bg-gradient-to-br from-gray-100 to-gray-200">
          <img
            src={movie.poster_url || 'https://via.placeholder.com/300x400/e2e8f0/64748b?text=No+Image'}
            alt={movie.title}
            className="w-full h-80 object-cover transition-transform duration-500 group-hover:scale-105"
            onError={(e) => {
              e.target.src = 'https://via.placeholder.com/300x400/e2e8f0/64748b?text=No+Image';
            }}
          />

          {/* Gradient overlay */}
          <div className="absolute inset-0 bg-gradient-to-t from-black/60 via-transparent to-transparent opacity-0 group-hover:opacity-100 transition-opacity duration-300" />

          {/* Overlay with movie info */}
          <div className="absolute bottom-0 left-0 right-0 p-4 text-white transform translate-y-full group-hover:translate-y-0 transition-transform duration-300 ease-out">
            <div className="flex items-center gap-2 mb-2">
              {renderStars(movie.avg_rating)}
              <span className="text-sm font-medium bg-black/20 rounded-lg px-2 py-1 backdrop-blur-sm">
                {movie.avg_rating ? movie.avg_rating.toFixed(1) : 'No rating'}
              </span>
            </div>

            {movie.plot && (
              <p className="text-sm text-gray-100 line-clamp-2 leading-relaxed">
                {truncatePlot(movie.plot)}
              </p>
            )}
          </div>
        </div>
      </div>

      <div className="p-4 space-y-3">
        <div>
          <div className="group cursor-pointer">
            <h3 className="font-bold text-lg text-gray-900 group-hover:text-blue-600 transition-colors duration-200 line-clamp-2" title={movie.title}>
              {movie.title}
            </h3>
          </div>
          <p className="text-gray-500 text-sm font-medium">{formatYear(movie.year)}</p>
        </div>

        {/* User's rating if available */}
        {userRating && (
          <div className="flex items-center gap-2 p-3 bg-gradient-to-r from-blue-50 to-indigo-50 rounded-xl border border-blue-100">
            <span className="text-sm font-medium text-blue-700">Your rating:</span>
            {renderStars(userRating.rating)}
          </div>
        )}

        {/* Quick rating for authenticated users */}
        {isAuthenticated && !userRating && (
          <div className="space-y-2">
            {!showQuickRate ? (
              <button
                onClick={(e) => {
                  e.stopPropagation();
                  setShowQuickRate(true);
                }}
                className="w-full flex items-center justify-center gap-2 py-3 px-4 bg-gradient-to-r from-yellow-400 to-orange-500 hover:from-yellow-500 hover:to-orange-600 text-white font-semibold rounded-xl transition-all duration-200 hover:shadow-lg active:scale-95 disabled:opacity-50 disabled:cursor-not-allowed"
                disabled={isRating}
              >
                <svg className="w-4 h-4" viewBox="0 0 24 24" fill="currentColor">
                  <path d="M12 2l3.09 6.26L22 9.27l-5 4.87 1.18 6.88L12 17.77l-6.18 3.25L7 14.14 2 9.27l6.91-1.01L12 2z" />
                </svg>
                Quick Rate
              </button>
            ) : (
              <div className="p-4 bg-gradient-to-br from-gray-50 to-gray-100 rounded-xl border-2 border-dashed border-gray-300" onClick={(e) => e.stopPropagation()}>
                <div className="flex items-center justify-between mb-3">
                  <span className="text-sm font-semibold text-gray-700">Rate this movie:</span>
                  <button
                    onClick={() => setShowQuickRate(false)}
                    className="p-1.5 hover:bg-gray-200 rounded-full transition-colors duration-150"
                    type="button"
                  >
                    <svg className="w-4 h-4 text-gray-500" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                      <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M6 18L18 6M6 6l12 12" />
                    </svg>
                  </button>
                </div>
                <div className="flex justify-center">
                  {renderStars(quickRating, true)}
                </div>
              </div>
            )}
          </div>
        )}

        {/* Movie metadata */}
        <div className="flex items-center justify-between text-xs">
          {movie.rating_count > 0 && (
            <span className="flex items-center gap-1 text-gray-500">
              <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17 8h2a2 2 0 012 2v6a2 2 0 01-2 2h-2v4l-4-4H9a1.994 1.994 0 01-2-2V10a2 2 0 012-2h2V4a2 2 0 012-2h4a2 2 0 012 2v4z" />
              </svg>
              {movie.rating_count} rating{movie.rating_count !== 1 ? 's' : ''}
            </span>
          )}

          {showRecommendationScore && movie.recommendation_score && (
            <span className="flex items-center gap-1 text-green-600 font-semibold bg-green-50 px-2 py-1 rounded-full">
              <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M4.318 6.318a4.5 4.5 0 000 6.364L12 20.364l7.682-7.682a4.5 4.5 0 00-6.364-6.364L12 7.636l-1.318-1.318a4.5 4.5 0 00-6.364 0z" />
              </svg>
              {(movie.recommendation_score * 20).toFixed(0)}% match
            </span>
          )}
        </div>

        {/* Genres */}
        {movie.genres && movie.genres.length > 0 && (
          <div className="flex flex-wrap gap-1.5">
            {movie.genres.slice(0, 2).map(genre => (
              <span key={genre} className="px-2.5 py-1 bg-gradient-to-r from-gray-100 to-gray-200 text-gray-700 text-xs font-medium rounded-full hover:from-gray-200 hover:to-gray-300 transition-all duration-150 cursor-pointer">
                {genre}
              </span>
            ))}
            {movie.genres.length > 2 && (
              <span className="px-2.5 py-1 bg-gradient-to-r from-blue-100 to-indigo-100 text-blue-700 text-xs font-medium rounded-full">
                +{movie.genres.length - 2} more
              </span>
            )}
          </div>
        )}
      </div>

      {/* Loading overlay for rating */}
      {isRating && (
        <div className="absolute inset-0 bg-white/90 backdrop-blur-sm flex items-center justify-center rounded-2xl">
          <div className="flex flex-col items-center gap-3">
            <div className="w-8 h-8 border-3 border-blue-500 border-t-transparent rounded-full animate-spin"></div>
            <span className="text-sm font-semibold text-gray-700">Rating movie...</span>
          </div>
        </div>
      )}
    </div>
  );
};

// Demo component with sample data
const ModernMovieCardDemo = () => {
  const sampleMovies = [
    {
      id: 1,
      title: "The Dark Knight",
      year: 2008,
      poster_url: "https://images.unsplash.com/photo-1594736797933-d0401ba2fe65?w=300&h=400&fit=crop",
      avg_rating: 4.5,
      rating_count: 1234,
      plot: "When the menace known as The Joker emerges from his mysterious past, he wreaks havoc and chaos on the people of Gotham. The Dark Knight must accept one of the greatest psychological and physical tests to fight injustice.",
      genres: ["Action", "Crime", "Drama", "Thriller"],
      recommendation_score: 0.95
    },
    {
      id: 2,
      title: "Inception",
      year: 2010,
      poster_url: "https://images.unsplash.com/photo-1440404653325-ab127d49abc1?w=300&h=400&fit=crop",
      avg_rating: 4.3,
      rating_count: 987,
      plot: "A thief who steals corporate secrets through the use of dream-sharing technology is given the inverse task of planting an idea into the mind of a C.E.O.",
      genres: ["Sci-Fi", "Thriller", "Action"],
      recommendation_score: 0.87
    },
    {
      id: 3,
      title: "Pulp Fiction",
      year: 1994,
      poster_url: "https://images.unsplash.com/photo-1489599904797-7de7ed38bb6b?w=300&h=400&fit=crop",
      avg_rating: 4.4,
      rating_count: 567,
      plot: "The lives of two mob hitmen, a boxer, a gangster and his wife intertwine in four tales of violence and redemption.",
      genres: ["Crime", "Drama"],
      recommendation_score: 0.92
    }
  ];

  return (
    <div className="min-h-screen bg-gradient-to-br from-gray-50 to-gray-100 p-8">
      <div className="max-w-7xl mx-auto">
        <div className="text-center mb-12">
          <h1 className="text-4xl font-bold text-gray-900 mb-4">Modern Movie Card UI</h1>
          <p className="text-gray-600 text-lg">Sleek, interactive movie cards with modern design principles</p>
        </div>

        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-8">
          {sampleMovies.map((movie, index) => (
            <MovieCard
              key={movie.id}
              movie={movie}
              showRecommendationScore={index < 2}
              recommendationSources={
                index === 0 ? ['collaborative', 'content'] :
                index === 1 ? ['collaborative'] :
                ['content']
              }
              onRatingUpdate={(movieId, rating) => {
                console.log(`Movie ${movieId} rated ${rating} stars`);
              }}
            />
          ))}
        </div>

        <div className="mt-16 p-8 bg-white rounded-2xl shadow-lg border border-gray-100">
          <h2 className="text-2xl font-bold text-gray-900 mb-6">Modern UI Features</h2>
          <div className="grid md:grid-cols-2 gap-6">
            <div className="space-y-4">
              <div className="flex items-start gap-3">
                <div className="w-2 h-2 bg-blue-500 rounded-full mt-2 flex-shrink-0"></div>
                <div>
                  <h3 className="font-semibold text-gray-900">Interactive Hover Effects</h3>
                  <p className="text-gray-600 text-sm">Smooth animations and transitions on hover with poster scaling and overlay reveals</p>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <div className="w-2 h-2 bg-green-500 rounded-full mt-2 flex-shrink-0"></div>
                <div>
                  <h3 className="font-semibold text-gray-900">Gradient Accents</h3>
                  <p className="text-gray-600 text-sm">Modern gradient backgrounds for buttons and recommendation badges</p>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <div className="w-2 h-2 bg-purple-500 rounded-full mt-2 flex-shrink-0"></div>
                <div>
                  <h3 className="font-semibold text-gray-900">Interactive Rating System</h3>
                  <p className="text-gray-600 text-sm">Animated star ratings with hover effects and quick rating functionality</p>
                </div>
              </div>
            </div>
            <div className="space-y-4">
              <div className="flex items-start gap-3">
                <div className="w-2 h-2 bg-yellow-500 rounded-full mt-2 flex-shrink-0"></div>
                <div>
                  <h3 className="font-semibold text-gray-900">Smart Recommendation Badges</h3>
                  <p className="text-gray-600 text-sm">Color-coded badges indicating recommendation sources with subtle animations</p>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <div className="w-2 h-2 bg-red-500 rounded-full mt-2 flex-shrink-0"></div>
                <div>
                  <h3 className="font-semibold text-gray-900">Loading States</h3>
                  <p className="text-gray-600 text-sm">Elegant loading overlays with blur effects and animated spinners</p>
                </div>
              </div>
              <div className="flex items-start gap-3">
                <div className="w-2 h-2 bg-indigo-500 rounded-full mt-2 flex-shrink-0"></div>
                <div>
                  <h3 className="font-semibold text-gray-900">Responsive Design</h3>
                  <p className="text-gray-600 text-sm">Fully responsive layout that works beautifully on all screen sizes</p>
                </div>
              </div>
            </div>
          </div>
        </div>

        <div className="mt-8 text-center">
          <p className="text-gray-500 text-sm">
            All backend functionality preserved - simply replace the styling in your existing component
          </p>
        </div>
      </div>
    </div>
  );
};

export default ModernMovieCardDemo;
